// Парсим вход
const msg = $input.first().json;
const text = msg.message?.text || '';
const callbackData = msg.callback_query?.data || '';
const chatId = msg.message?.chat?.id || msg.callback_query?.message?.chat?.id;
const userId = msg.message?.from?.id || msg.callback_query?.from?.id;
const callbackQueryId = msg.callback_query?.id || null;

// Тарифы (поменяйте под себя)
const TARIFFS = {
  basic: { title: 'Базовый', desc: 'Доступ на месяц', amount: 199 },
  pro:   { title: 'Профи',   desc: 'Доступ на год',   amount: 1499 }
};

let action = 'unknown';
let tierKey = null;

if (text === '/pay' || text === '/start') {
  action = 'show_tariffs';
} else if (callbackData.startsWith('pay:')) {
  action = 'create_payment';
  tierKey = callbackData.split(':')[1];
}

return [{ json: { action, tierKey, chatId, userId, callbackQueryId, tariffs: TARIFFS } }];

// Формируем меню тарифов
const r = $input.first().json;
const text = '💎 <b>Выберите тариф</b>\n\n' +
  Object.entries(r.tariffs).map(([k,t]) => `<b>${t.title}</b> — ${t.amount} ₽\n${t.desc}`).join('\n\n');

const buttons = Object.entries(r.tariffs).map(([k,t]) => [{ text: `💳 ${t.title} ${t.amount} ₽`, callback_data: `pay:${k}` }]);

return [{
  json: {
    chat_id: r.chatId,
    text,
    parse_mode: 'HTML',
    reply_markup: { inline_keyboard: buttons }
  }
}];

// Формируем тело запроса к YooKassa
const r = $input.first().json;
const tier = r.tariffs[r.tierKey];
if (!tier) throw new Error('Unknown tier: ' + r.tierKey);

// Idempotence key чтобы повторные клики не плодили платежи
const bucket = Math.floor(Date.now() / (5*60*1000)); // 5-минутное окно
const idempotenceKey = `tg-${r.chatId}-${r.tierKey}-${tier.amount}-${bucket}`;

const ykBody = {
  amount: { value: tier.amount.toFixed(2), currency: 'RUB' },
  capture: true,
  confirmation: {
    type: 'redirect',
    return_url: 'https://t.me/YOUR_BOT_USERNAME' // ВАЖНО: замените на свой бот
  },
  description: `${tier.title} (${r.chatId})`,
  metadata: {
    chat_id: String(r.chatId),
    tier_key: r.tierKey,
    user_id: String(r.userId)
  },
  receipt: {
    customer: { email: `${r.chatId}@yourbot.example` }, // FZ-54: поменяйте на реальный сбор email
    items: [{
      description: tier.title,
      quantity: '1.00',
      amount: { value: tier.amount.toFixed(2), currency: 'RUB' },
      vat_code: 1,
      payment_mode: 'full_payment',
      payment_subject: 'service'
    }]
  }
};

return [{ json: { chat_id: r.chatId, callback_query_id: r.callbackQueryId, tier_title: tier.title, idempotence_key: idempotenceKey, yk_body: ykBody } }];

// Готовим ответ пользователю со ссылкой на оплату
const r = $('Build YK Payment').first().json;
const yk = $input.first().json;

return [{
  json: {
    chat_id: r.chat_id,
    text: `💳 <b>Оплата тарифа «${r.tier_title}»</b>\n\nНажмите кнопку ниже чтобы открыть страницу оплаты YooKassa. После успешной оплаты вы автоматически получите уведомление.`,
    parse_mode: 'HTML',
    reply_markup: {
      inline_keyboard: [[
        { text: '💳 Оплатить', url: yk.confirmation.confirmation_url }
      ]]
    }
  }
}];
